// Worked example: prove that f(n) = 3n + 5 is O(n).
//
// We want constants c and n₀ such that 3n + 5 ≤ c · n for all n ≥ n₀.
//
// Try c = 4. Then we need 3n + 5 ≤ 4n, i.e. 5 ≤ n.
// So n₀ = 5 works:
//
//    n   3n+5    4n
//    5    20     20  ✓ equal
//    6    23     24  ✓
//    7    26     28  ✓
//   10    35     40  ✓
//
// Therefore 3n + 5 = O(n), with c = 4, n₀ = 5.

function f(n) { return 3 * n + 5; }
function cg(n) { return 4 * n; }

for (let n = 1; n <= 10; n++) {
  console.log(`n=${n}  f=${f(n)}  c·g=${cg(n)}  ${f(n) <= cg(n) ? 'OK' : 'NO'}`);
}

// Sometimes the constant DOES matter — but Big O hides it.
//
// Algorithm A: 100n operations  → O(n)
// Algorithm B:   n² operations   → O(n²)
//
// When is B actually faster?  When n² < 100n, i.e. n < 100.
//
// For small n, the 'worse' algorithm can win.
// That's a real engineering consideration — but Big O notation
// intentionally ignores it.

const sizes = [10, 50, 100, 500, 1000];
console.log('  n  |  100n   |   n²   | which wins');
console.log('-----+---------+--------+------------');
for (const n of sizes) {
  const a = 100 * n;
  const b = n * n;
  const winner = a < b ? 'A (100n)' : 'B (n²)';
  console.log(`${String(n).padStart(4)}  | ${String(a).padStart(7)} | ${String(b).padStart(6)} | ${winner}`);
}
